arguments.file_text:
namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeCategory
{
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public string Icon { get; set; } = string.Empty;
    public int RecipeCount { get; set; }
}

@using RecipeHub.Services
@rendermode InteractiveServer
@inject RecipeService RecipeService

<div class="star-rating">
    <span class="rating-label">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= _currentRating ? "filled" : "")"
              @onclick="() => Rate(star)"
              title="@star star(s)">
            @(star <= _currentRating ? "★" : "☆")
        </span>
    }
    @if (_hasRated)
    {
        <span class="rating-confirmation">Thanks for rating!</span>
    }
    <div class="average-rating">
        Average: @AverageRating.ToString("F1") / 5 (@RatingCount ratings)
    </div>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int _currentRating;
    private bool _hasRated;

    private void Rate(int stars)
    {
        _currentRating = stars;
        _hasRated = true;
        RecipeService.RateRecipe(RecipeId, stars);
        var recipe = RecipeService.GetRecipeById(RecipeId);
        if (recipe != null)
        {
            AverageRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
    }
}

