.star-rating {
    margin: 1rem 0;
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 8px;
}

.star-rating .rating-label {
    display: block;
    margin-bottom: 0.5rem;
    font-weight: 600;
}

.star-rating .star {
    font-size: 1.8rem;
    cursor: pointer;
    transition: transform 0.1s;
    color: #ccc;
}

.star-rating .star:hover {
    transform: scale(1.2);
}

.star-rating .star.filled {
    color: #ffc107;
}

.star-rating .rating-confirmation {
    margin-left: 1rem;
    color: #28a745;
    font-weight: 500;
}

.star-rating .average-rating {
    margin-top: 0.5rem;
    font-size: 0.9rem;
    color: #6c757d;
}

@page "/category/{CategoryName}"
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes - RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@if (Recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category yet.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">
                            ★ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private List<RecipeHub.Models.Recipe> Recipes { get; set; } = new();

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeHub.Services
@using RecipeHub.Components.Shared
@inject RecipeService RecipeService

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeHub</PageTitle>

@if (Recipe == null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/category/@Recipe.Category">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        </ol>
    </nav>

    <h1>@Recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@Recipe.Category</span>

    <div class="row mt-4">
        <div class="col-md-4">
            <div class="card">
                <div class="card-header"><strong>Ingredients</strong></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in Recipe.Ingredients.Split('\n'))
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>

        <div class="col-md-8">
            <div class="card">
                <div class="card-header"><strong>Instructions</strong></div>
                <div class="card-body">
                    @foreach (var step in Recipe.Steps.Split('\n'))
                    {
                        <p>@step</p>
                    }
                </div>
            </div>
        </div>
    </div>

    <StarRating RecipeId="@Recipe.Id" AverageRating="@Recipe.AverageRating" RatingCount="@Recipe.RatingCount" />
}

@code {
    [Parameter] public int Id { get; set; }

    private RecipeHub.Models.Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetRecipeById(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "@_model.Title" has been added to the @_model.Category category.
        <a href="/category/@_model.Category">View category</a>
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" class="mt-4">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="_model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="_model.Category" class="form-select">
                <option value="">-- Select a category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Mexican">Mexican</option>
                <option value="Asian">Asian</option>
                <option value="Desserts">Desserts</option>
                <option value="Salads">Salads</option>
            </InputSelect>
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="_model.Ingredients" class="form-control" rows="6" placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="_model.Steps" class="form-control" rows="6" placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients&#10;3. Add wet ingredients" />
        </div>

        <button type="submit" class="btn btn-success" disabled="@_isProcessing">
            @if (_isProcessing)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Submit Recipe
        </button>
    </EditForm>
}

@code {
    private Recipe _model = new();
    private bool _submitted;
    private bool _isProcessing;

    private void HandleSubmit()
    {
        _isProcessing = true;

        if (string.IsNullOrWhiteSpace(_model.Title) ||
            string.IsNullOrWhiteSpace(_model.Category) ||
            string.IsNullOrWhiteSpace(_model.Ingredients) ||
            string.IsNullOrWhiteSpace(_model.Steps))
        {
            _isProcessing = false;
            return;
        }

        RecipeService.AddRecipe(_model);
        _submitted = true;
        _isProcessing = false;
    }
}

